import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';

function App() {
  const [view, setView] = useState('home');
  const [campeonatos, setCampeonatos] = useState([]);
  
  const [nome, setNome] = useState('');
  const [formato, setFormato] = useState('pontos-corridos');
  const [qtdTimes, setQtdTimes] = useState(16);

  const [campeonatoAtivo, setCampeonatoAtivo] = useState(null);
  const [times, setTimes] = useState([]);
  const [partidas, setPartidas] = useState([]); // NOVO: Estado das partidas
  const [nomeTime, setNomeTime] = useState('');
  const [nomeResponsavel, setNomeResponsavel] = useState('');

  // 1. Carregar Campeonatos
  const carregarCampeonatos = async () => {
    const { data, error } = await supabase
      .from('campeonatos')
      .select('*')
      .order('created_at', { ascending: false });
    if (!error) setCampeonatos(data);
  };

  useEffect(() => { carregarCampeonatos(); }, []);

  const criarCampeonatoReal = async (e) => {
    e.preventDefault();
    const { error } = await supabase
      .from('campeonatos')
      .insert([{ nome, formato, qtd_times: qtdTimes }]);
    if (!error) {
      setNome(''); setFormato('pontos-corridos'); setQtdTimes(16);
      carregarCampeonatos(); setView('home'); 
    }
  };

  // Abrir tela de Detalhes
  const abrirDetalhes = async (campeonato) => {
    setCampeonatoAtivo(campeonato);
    setView('detalhes');
    carregarTimes(campeonato.id);
    carregarPartidas(campeonato.id); // NOVO: Carrega os jogos ao abrir
  };

  const carregarTimes = async (campeonatoId) => {
    const { data, error } = await supabase
      .from('times')
      .select('*')
      .eq('campeonato_id', campeonatoId)
      .order('created_at', { ascending: true });
    if (!error) setTimes(data);
  };

  // NOVO: Buscar as partidas já trazendo o nome dos times (Relacionamento SQL)
  const carregarPartidas = async (campeonatoId) => {
    const { data, error } = await supabase
      .from('partidas')
      .select(`
        *,
        time_casa:time_casa_id(nome),
        time_fora:time_fora_id(nome)
      `)
      .eq('campeonato_id', campeonatoId)
      .order('rodada', { ascending: true })
      .order('created_at', { ascending: true });
    
    if (!error) setPartidas(data);
  };

  const adicionarTime = async (e) => {
    e.preventDefault();
    if (times.length >= campeonatoAtivo.qtd_times) {
      alert(`Limite de times atingido!`); return;
    }
    const { error } = await supabase
      .from('times')
      .insert([{ campeonato_id: campeonatoAtivo.id, nome: nomeTime, jogador_responsavel: nomeResponsavel }]);
    if (!error) { setNomeTime(''); setNomeResponsavel(''); carregarTimes(campeonatoAtivo.id); }
  };

  const removerTime = async (timeId) => {
    await supabase.from('times').delete().eq('id', timeId);
    carregarTimes(campeonatoAtivo.id);
  };

  // ==========================================
  // NOVO: ALGORITMO PARA GERAR TABELA DE JOGOS
  // ==========================================
  const gerarTabelaJogos = async () => {
    if (times.length < 2) {
      alert("Você precisa de pelo menos 2 times para gerar a tabela!");
      return;
    }
    if (partidas.length > 0) {
      alert("A tabela já foi gerada para este campeonato!");
      return;
    }

    let timesSorteio = [...times];
    
    // Se o número de times for ímpar, adicionamos um "fantasma" (quem jogar contra ele, folga na rodada)
    if (timesSorteio.length % 2 !== 0) {
      timesSorteio.push({ id: null, nome: 'FOLGA' });
    }

    const totalRodadas = timesSorteio.length - 1;
    const metade = timesSorteio.length / 2;
    const novasPartidas = [];

    // Algoritmo Round-Robin
    for (let rodada = 1; rodada <= totalRodadas; rodada++) {
      for (let i = 0; i < metade; i++) {
        const casa = timesSorteio[i];
        const fora = timesSorteio[timesSorteio.length - 1 - i];

        // Se nenhum dos dois for o time "fantasma", cria a partida
        if (casa.id !== null && fora.id !== null) {
          novasPartidas.push({
            campeonato_id: campeonatoAtivo.id,
            time_casa_id: casa.id,
            time_fora_id: fora.id,
            rodada: rodada,
            status: 'agendado'
          });
        }
      }
      // Gira os times (trava o índice 0 e move o último para a posição 1)
      timesSorteio.splice(1, 0, timesSorteio.pop());
    }

    // Salva tudo no Supabase de uma vez
    const { error } = await supabase.from('partidas').insert(novasPartidas);
    if (error) {
      console.error("Erro ao gerar tabela", error);
      alert("Erro ao gerar tabela.");
    } else {
      carregarPartidas(campeonatoAtivo.id);
      alert("Tabela gerada com sucesso!");
    }
  };

  // NOVO: Atualizar o placar de um jogo
  const atualizarPlacar = async (partidaId, golsCasa, golsFora) => {
    const { error } = await supabase
      .from('partidas')
      .update({ 
        gols_casa: golsCasa, 
        gols_fora: golsFora, 
        status: 'finalizado' 
      })
      .eq('id', partidaId);
    
    if (!error) carregarPartidas(campeonatoAtivo.id);
  };


  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans pb-10">
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card sticky top-0 z-50">
        <h1 className="text-2xl font-bold italic text-ef-green cursor-pointer" onClick={() => setView('home')}>eFOOTBALL CHAMP</h1>
        <div className="space-x-6">
          <button onClick={() => setView('home')} className="hover:text-ef-green transition">Campeonatos</button>
        </div>
      </nav>

      <main className="p-8 max-w-6xl mx-auto">
        
        {/* TELA 1: HOME */}
        {view === 'home' && (
          <>
            <header className="mb-10">
              <h2 className="text-4xl font-extrabold">Gerencie seus Torneios</h2>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {campeonatos.map((champ) => (
                <div key={champ.id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 hover:border-ef-green transition">
                  <div className="bg-ef-green text-black text-xs font-bold px-2 py-1 rounded mb-4 inline-block">OPEN</div>
                  <h3 className="text-xl font-bold mb-2">{champ.nome}</h3>
                  <p className="text-gray-400 text-sm">{champ.qtd_times} Times • {champ.formato}</p>
                  <button onClick={() => abrirDetalhes(champ)} className="mt-6 w-full py-2 border border-ef-green text-ef-green rounded-lg hover:bg-ef-green hover:text-black">Gerenciar</button>
                </div>
              ))}
              <div onClick={() => setView('criar')} className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex flex-col items-center justify-center text-gray-500 hover:text-ef-green hover:border-ef-green cursor-pointer">
                 <span className="text-4xl mb-2">+</span><p className="font-bold">Criar Campeonato</p>
              </div>
            </div>
          </>
        )}

        {/* TELA 2: CRIAR CAMPEONATO (Ocultada aqui para economizar espaço visual, mas o código é o mesmo que você já tem) */}
        {view === 'criar' && (
           <div className="max-w-2xl mx-auto bg-ef-card p-8 rounded-2xl border border-gray-800">
             <h2 className="text-3xl font-bold mb-6 border-b border-gray-800 pb-4">Novo Campeonato</h2>
             <form onSubmit={criarCampeonatoReal} className="space-y-6">
               <div><label className="block text-gray-400 mb-2">Nome</label><input type="text" required value={nome} onChange={(e) => setNome(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:border-ef-green" /></div>
               <div className="grid grid-cols-2 gap-6">
                 <div><label className="block text-gray-400 mb-2">Formato</label><select value={formato} onChange={(e) => setFormato(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:border-ef-green"><option value="pontos-corridos">Pontos Corridos</option></select></div>
                 <div><label className="block text-gray-400 mb-2">Qtd Times</label><input type="number" required value={qtdTimes} onChange={(e) => setQtdTimes(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:border-ef-green" /></div>
               </div>
               <div className="flex space-x-4"><button type="button" onClick={() => setView('home')} className="flex-1 py-3 border border-gray-600 rounded-lg">Cancelar</button><button type="submit" className="flex-1 py-3 bg-ef-green text-black font-bold rounded-lg">Salvar</button></div>
             </form>
           </div>
        )}

        {/* TELA 3: DETALHES, TIMES E JOGOS */}
        {view === 'detalhes' && campeonatoAtivo && (
          <div>
            <button onClick={() => setView('home')} className="text-gray-400 hover:text-ef-green mb-6">← Voltar</button>
            
            <header className="mb-10 pb-6 border-b border-gray-800 flex justify-between items-end">
              <div>
                <h2 className="text-4xl font-extrabold text-ef-green">{campeonatoAtivo.nome}</h2>
                <p className="text-gray-400 mt-2">Times: {times.length} / {campeonatoAtivo.qtd_times}</p>
              </div>
              
              {/* BOTÃO MÁGICO PARA GERAR TABELA */}
              {partidas.length === 0 && times.length > 1 && (
                <button 
                  onClick={gerarTabelaJogos}
                  className="px-6 py-3 bg-ef-green text-black font-bold rounded-lg hover:bg-green-400 transition animate-pulse"
                >
                  Gerar Tabela de Jogos
                </button>
              )}
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              
              {/* COLUNA ESQUERDA: GESTÃO DE TIMES */}
              <div className="lg:col-span-1 space-y-8">
                {/* Add Time */}
                <div className="bg-ef-card p-6 rounded-2xl border border-gray-800">
                  <h3 className="text-xl font-bold mb-4">Adicionar Time</h3>
                  <form onSubmit={adicionarTime} className="space-y-4">
                    <input type="text" required value={nomeTime} onChange={(e) => setNomeTime(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white" placeholder="Nome do Time" />
                    <input type="text" required value={nomeResponsavel} onChange={(e) => setNomeResponsavel(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white" placeholder="Jogador (PSN/Xbox)" />
                    <button type="submit" disabled={times.length >= campeonatoAtivo.qtd_times || partidas.length > 0} className="w-full py-3 bg-ef-green text-black font-bold rounded-lg disabled:opacity-50">Adicionar</button>
                  </form>
                </div>

                {/* Lista de Times */}
                <div className="bg-ef-card p-6 rounded-2xl border border-gray-800">
                  <h3 className="text-xl font-bold mb-4">Times ({times.length})</h3>
                  <div className="space-y-2">
                    {times.map(t => (
                      <div key={t.id} className="flex justify-between items-center p-3 bg-ef-dark rounded-lg">
                        <span className="font-bold">{t.nome} <span className="text-xs text-gray-500 font-normal block">{t.jogador_responsavel}</span></span>
                        {partidas.length === 0 && <button onClick={() => removerTime(t.id)} className="text-red-500 text-sm">X</button>}
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* COLUNA DIREITA: TABELA DE JOGOS E PLACARES */}
              <div className="lg:col-span-2">
                <div className="bg-ef-card p-6 rounded-2xl border border-gray-800">
                  <h3 className="text-2xl font-bold mb-6 text-ef-green">Confrontos</h3>
                  
                  {partidas.length === 0 ? (
                    <div className="text-center text-gray-500 py-10">Adicione os times e clique em "Gerar Tabela de Jogos" lá em cima!</div>
                  ) : (
                    <div className="space-y-6">
                      {/* Agrupando os jogos por Rodada visualmente */}
                      {[...new Set(partidas.map(p => p.rodada))].map(rodada => (
                        <div key={rodada}>
                          <h4 className="text-lg font-bold border-b border-gray-700 pb-2 mb-4 text-gray-300">Rodada {rodada}</h4>
                          <div className="grid grid-cols-1 gap-4">
                            
                            {partidas.filter(p => p.rodada === rodada).map(partida => (
                              <div key={partida.id} className="flex items-center justify-between bg-ef-dark p-4 rounded-xl border border-gray-800">
                                
                                {/* Time Casa */}
                                <div className="flex-1 text-right font-bold text-lg pr-4">{partida.time_casa?.nome}</div>
                                
                                {/* Placar Central */}
                                <div className="flex items-center space-x-2 bg-black px-4 py-2 rounded-lg border border-gray-700">
                                  <input 
                                    type="number" 
                                    defaultValue={partida.gols_casa}
                                    onBlur={(e) => atualizarPlacar(partida.id, parseInt(e.target.value) || 0, partida.gols_fora)}
                                    className="w-10 text-center bg-transparent text-xl font-bold text-ef-green focus:outline-none" 
                                  />
                                  <span className="text-gray-500">X</span>
                                  <input 
                                    type="number" 
                                    defaultValue={partida.gols_fora}
                                    onBlur={(e) => atualizarPlacar(partida.id, partida.gols_casa, parseInt(e.target.value) || 0)}
                                    className="w-10 text-center bg-transparent text-xl font-bold text-ef-green focus:outline-none" 
                                  />
                                </div>
                                
                                {/* Time Fora */}
                                <div className="flex-1 text-left font-bold text-lg pl-4">{partida.time_fora?.nome}</div>
                                
                              </div>
                            ))}

                          </div>
                        </div>
                      ))}
                    </div>
                  )}

                </div>
              </div>

            </div>
          </div>
        )}

      </main>
    </div>
  );
}

export default App;
